app.disable('x-powered-by');

// --- Secure API Key Storage ---
// In production, store hashed API keys in a database
// Keys are stored as SHA-256 hashes to prevent exposure if the store is compromised
const apiKeyStore = new Map();

function hashApiKey(key) {
  return crypto.createHash('sha256').update(key).digest('hex');
}

// Register valid API keys (in production, do this via admin interface/DB)
function registerApiKey(plainKey, metadata) {
  const hashed = hashApiKey(plainKey);
  apiKeyStore.set(hashed, {
    ...metadata,
    createdAt: new Date().toISOString()
  });
}

// Seed some example keys (in production, load from secure storage)
registerApiKey('sk_live_abc123def456', { owner: 'service-a', tier: 'standard' });
