// --- Middleware: Extract API key securely ---
function extractApiKey(req, res, next) {
  req.requestId = generateRequestId();
  req.startTime = Date.now();

  // Accept API key from header (preferred) or query parameter
  // Header-based is more secure as query params can appear in server logs, browser history, etc.
  let apiKey = req.headers['x-api-key'] || req.query.api_key;

  if (req.query.api_key) {
    // Strip the API key from the query string to prevent it from being
    // forwarded in the URL to backend services or logged by proxies
    delete req.query.api_key;

    // Reconstruct the URL without the api_key parameter
    const url = new URL(req.originalUrl, `http://${req.headers.host}`);
    url.searchParams.delete('api_key');
    req.url = url.pathname + url.search;
  }

  req.apiKey = apiKey || null;
  next();
}

app.use(extractApiKey);

// --- Middleware: Authenticate API Key ---
function authenticateApiKey(req, res, next) {
  const apiKey = req.apiKey;

  if (!apiKey) {
    secureLog({
      requestId: req.requestId,
      method: req.method,
      path: req.path,
      apiKeyMasked: '[none]',
      statusCode: 401,
      responseTime: Date.now() - req.startTime,
      ip: req.ip,
      userAgent: req.get('user-agent')
    });
    return res.status(401).json({
      error: 'Authentication required',
      message: 'Please provide a valid API key via X-Api-Key header or api_key query parameter'
    });
  }

  // Validate using constant-time comparison against hashed keys
  const hashedKey = hashApiKey(apiKey);
  let matchedEntry = null;

  for (const [storedHash, metadata] of apiKeyStore.entries()) {
    // Use timing-safe comparison to prevent timing attacks
    const hashBuffer = Buffer.from(hashedKey, 'hex');
    const storedBuffer = Buffer.from(storedHash, 'hex');

    if (hashBuffer.length === storedBuffer.length && crypto.timingSafeEqual(hashBuffer, storedBuffer)) {
      matchedEntry = metadata;
      break;
    }
  }

  if (!matchedEntry) {
    secureLog({
      requestId: req.requestId,
      method: req.method,
      path: req.path,
      apiKeyMasked: maskApiKey(apiKey),
      statusCode: 403,
      responseTime: Date.now() - req.startTime,
      ip: req.ip,
      userAgent: req.get('user-agent')
    });
    return res.status(403).json({
      error: 'Forbidden',
      message: 'Invalid API key'
    });
  }

  req.apiKeyMetadata = matchedEntry;
  next();
}

